import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "../../styles/Admin/AdminDashboard.css";

const API = process.env.REACT_APP_API_URL || "http://localhost:5050";

export default function AdminDashboard() {
  const navigate = useNavigate();

  const [me, setMe] = useState(null);
  const [users, setUsers] = useState([]);
  const [loadingMe, setLoadingMe] = useState(true);
  const [loadingUsers, setLoadingUsers] = useState(true);
  const [error, setError] = useState("");

  const token = localStorage.getItem("token");

  useEffect(() => {
    if (!token) {
      navigate("/login");
      return;
    }

    const loadMe = async () => {
      try {
        setLoadingMe(true);
        setError("");
        const res = await fetch(`${API}/api/admin/me`, {
          headers: { Authorization: `Bearer ${token}` },
        });

        const data = await res.json();
        if (!res.ok) throw new Error(data?.message || "Not authorized");

        setMe(data.user);
      } catch (e) {
        setError(e.message);
      } finally {
        setLoadingMe(false);
      }
    };

    loadMe();
  }, [token, navigate]);

  const loadUsers = async () => {
    try {
      setLoadingUsers(true);
      setError("");
      const res = await fetch(`${API}/api/admin/users`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data?.message || "Failed to load users");
      setUsers(data.users || []);
    } catch (e) {
      setError(e.message);
    } finally {
      setLoadingUsers(false);
    }
  };

  useEffect(() => {
    if (!token) return;
    loadUsers();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [token]);

  const makeAdmin = async (userId) => {
    try {
      setError("");
      const res = await fetch(`${API}/api/admin/users/${userId}/make-admin`, {
        method: "PATCH",
        headers: {
          Authorization: `Bearer ${token}`,
          "Content-Type": "application/json",
        },
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data?.message || "Failed to promote user");

      // refresh list
      await loadUsers();
    } catch (e) {
      setError(e.message);
    }
  };

  const logout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    navigate("/login");
  };

  return (
    <div className="admin-page">
      <div className="admin-container">
        <div className="admin-header">
          <div>
            <h1 className="admin-title">Admin Dashboard</h1>
            <p className="admin-subtitle">Manage users (role-based access)</p>
          </div>

          <button className="admin-btn admin-btn-outline" onClick={logout}>
            Logout
          </button>
        </div>

        {error && <div className="admin-alert">{error}</div>}

        <div className="admin-cards">
          <div className="admin-card">
            <h3>Session</h3>

            {loadingMe ? (
              <p className="admin-muted">Loading...</p>
            ) : me ? (
              <div className="admin-kv">
                <div>
                  <span className="admin-k">Name</span>
                  <span className="admin-v">{me.firstName} {me.lastName}</span>
                </div>
                <div>
                  <span className="admin-k">Email</span>
                  <span className="admin-v">{me.email}</span>
                </div>
                <div>
                  <span className="admin-k">Role</span>
                  <span className={`admin-pill ${me.role === "admin" ? "pill-admin" : ""}`}>
                    {me.role}
                  </span>
                </div>
              </div>
            ) : (
              <p className="admin-muted">Not authorized.</p>
            )}
          </div>

          <div className="admin-card">
            <div className="admin-card-top">
              <h3>Users</h3>
              <button
                className="admin-btn"
                onClick={loadUsers}
                disabled={loadingUsers}
              >
                {loadingUsers ? "Refreshing..." : "Refresh"}
              </button>
            </div>

            {loadingUsers ? (
              <p className="admin-muted">Loading users...</p>
            ) : users.length === 0 ? (
              <p className="admin-muted">No users found.</p>
            ) : (
              <div className="admin-table">
                <div className="admin-row admin-head">
                  <div>Name</div>
                  <div>Email</div>
                  <div>Role</div>
                  <div>Action</div>
                </div>

                {users.map((u) => (
                  <div key={u._id || u.id} className="admin-row">
                    <div>{u.firstName} {u.lastName}</div>
                    <div className="admin-email">{u.email}</div>
                    <div>
                      <span className={`admin-pill ${u.role === "admin" ? "pill-admin" : ""}`}>
                        {u.role || "user"}
                      </span>
                    </div>
                    <div>
                      {u.role === "admin" ? (
                        <button className="admin-btn admin-btn-disabled" disabled>
                          Admin
                        </button>
                      ) : (
                        <button
                          className="admin-btn"
                          onClick={() => makeAdmin(u._id || u.id)}
                        >
                          Make Admin
                        </button>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        <p className="admin-foot">
          Tip: If you can’t open this page, confirm your token includes <b>role</b> and your user in DB has <b>role: "admin"</b>.
        </p>
      </div>
    </div>
  );
}
